public class TraitementStream {
    public static int calculerSommeCarresPairs(List<Integer> nombres) {
        // Pipelines déclaratifs d'opérations sur collections
        return nombres.stream()
            .filter(n -> n != null)
            .filter(n -> n % 2 == 0)
            .mapToInt(n -> n * n) // Évite le boxing Integer inutile
            .sum();
    }

    public static Map<Boolean, List<Integer>> partitionner(List<Integer> nombres) {
        // Création d'une collection immuable avec List.of() (Java 9+)
        List<Integer> source = List.of(1, 2, 3, 4, 5, 6);

        return source.stream()
            .collect(Collectors.partitioningBy(n -> n % 2 == 0));
    }
}

