import java.lang.annotation.*;
import java.lang.reflect.Field;
import java.util.List;

// 1. Annotation personnalisée pour la métaprogrammation
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.FIELD)
@interface ValiderLongueur { int max(); }

// 2. Class générique avec variance (PECS: Producer Extends, Consumer Super)
public class GestionnaireDonnees<T> {

    public static void copierNombres(List<? extends Number> source, List<? super Number> destination) {
        destination.addAll(source);
    }

    // 3. Inspection par Réflexion au runtime
    public static void inspecterObjet(Object obj) throws Exception {
        Class<?> clazz = obj.getClass();
        for (Field champ : clazz.getDeclaredFields()) {
            champ.setAccessible(true);
            if (champ.isAnnotationPresent(ValiderLongueur.class)) {
                ValiderLongueur annot = champ.getAnnotation(ValiderLongueur.class);
                String val = (String) champ.get(obj);
                if (val != null && val.length() > annot.max()) {
                    throw new IllegalStateException("Champ trop long : " + champ.getName());
                }
            }
        }
    }
}

